                    new_principle.get("conflict_score", 0) + contradiction_score
                )
                existing["conflict_score"] = (
                    existing.get("conflict_score", 0) + contradiction_score
                )

                # Record the specific contradiction
                contradiction_id = f"{new_principle['id']}_{existing['id']}"
                self.contradiction_matrix[contradiction_id] = {
                    "principle_a": new_principle["id"],
                    "principle_b": existing["id"],
                    "score": contradiction_score,
                    "evidence": self.collect_contradiction_evidence(
                        new_principle, existing
                    ),
                    "timestamp": datetime.now(),
                    "resolved": False
                }

                conflicts.append({
                    "existing_principle": existing,
                    "contradiction_score": contradiction_score
                })

        return conflicts

    def calculate_contradiction(self, statement_a, statement_b):
        """
        Multi-dimensional contradiction detection
        """
        scores = {
            "semantic": self.semantic_contradiction(statement_a, statement_b),
            "logical": self.logical_contradiction(statement_a, statement_b),
            "empirical": self.empirical_contradiction(statement_a, statement_b)
        }

        # Weighted combination based on principle type
        weights = self.get_contradiction_weights(statement_a, statement_b)
        return sum(scores[k] * weights[k] for k in scores)
