        }
    ]

    def resolve_conflict(self, principle_a, principle_b, context=None):
        """
        Determine which principle takes precedence
        """
        scores = {"a": 0.0, "b": 0.0}

        for rule in self.PRECEDENCE_RULES:
            # Apply rule with context adjustment
            rule_score = rule["function"](principle_a, principle_b)
            adjusted_weight = self.context_adjust_weight(rule, context)

            if rule_score > 0.5:
                scores["a"] += adjusted_weight
            elif rule_score < 0.5:
                scores["b"] += adjusted_weight
            # Tie (0.5) gives no points to either

        # Determine winner with confidence threshold
        if scores["a"] - scores["b"] > PRECEDENCE_THRESHOLD:
            return {"winner": principle_a, "confidence": scores["a"]}
        elif scores["b"] - scores["a"] > PRECEDENCE_THRESHOLD:
            return {"winner": principle_b, "confidence": scores["b"]}
        else:
            # Ambiguous case - mark for human review
            return {"winner": None, "status": "requires_review"}
